(()=>{(function(){function n(t){return t<10?"0"+t:t}function o(){let t=document.getElementById("runningtime");if(!t)return;let r=t.dataset.startDate;if(!r)return;let s=new Date(r),e=new Date-s;if(isNaN(e)||e<0){t.textContent="\u65F6\u95F4\u5F02\u5E38";return}let a=Math.floor(e/(1e3*60*60*24)),i=Math.floor(e/(1e3*60*60)%24),c=Math.floor(e/(1e3*60)%60),u=Math.floor(e/1e3%60);t.textContent=`${a} \u5929 ${n(i)} : ${n(c)} : ${n(u)}`}document.addEventListener("DOMContentLoaded",()=>{o(),setInterval(o,1e3)})})();})();
